var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"따라서 관리국은 리플레이서 사태와 같은 범세계적 재난에\\n대처하고자, 태스크포스 간의 긴밀한 연대를 권장하려 합니다.","JPN":"したがって、管理局はリプレイサー事件のような世界規模の災害に\\n対処するべく、タスクフォース同士の緊密な連携を推奨します。","ENG":"[[","TWN":"因此管理局爲了應對像克隆集團事件一樣的全球性災難，\\n鼓勵特遣勢力之間的緊密合作。","THA":"ด้วยเหตุนี้ องค์การบริหารโลกเลยขอแนะนำให้ใช้\\nการสนธิกำลังของทาสก์ฟอร์สทั้งหมดเป็นหนึ่งเดียว\\nเพื่อสามารถตอบโต้วิกฤติระดับโลก\\nอย่างเหตุการณ์รีเพลสเซอร์ได้อย่างมีประสิทธิภาพ","VTN":"Do đó, Cục Quản Lý đề nghị thiết lập liên minh hợp tác xuyên suốt tất cả các TASKFORCES\\nđể phản ứng hiệu quả đối với các khủng hoảng toàn cầu như Sự Cố Nhân Bản.","SCN":"鉴于此，管理局鼓励特遣势力之间建立紧密联系\\n以应对与克隆集团事件类似的世界性灾难。","DEU":"Daher empfiehlt die Administration eine reibungslose Koalition über alle TASKFORCES hinweg,\\num wirksam auf globale Krisen wie den Replacer-Zwischenfall reagieren zu können.","FRA":"C'est pourquoi l'Administration recommande une coalition soudée entre toutes les divisions TASKFORCE\\nafin d'assurer une réponse efficace aux crises globales telles que l'incident des substituts."},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"이러한 방침에 따라, 관리국 인증을 받은 조직 간의\\n연합체 구성 초안을 전달드리오니......","JPN":"このような方針に基づき、管理局の認証を受けた組織間の\\n連合体構成の草案をお届けしますので……","ENG":"[[","TWN":"因應此方針，而提出在獲得管理局認可的組織之間組成聯盟的草案…","THA":"ด้วยนโยบายใหม่ของเรานี้ โปรดดูร่างข้อเสนอในการสนธิกำลัง\\nระหว่างองค์การต่างๆ ที่องค์การบริหารโลกให้การรับรอง ตามที่แนบมา...","VTN":"Dựa trên chính sách mới này, hãy xem bản nháp đính kèm\\ncủa đề xuất thành lập liên minh giữa các tổ chức được Cục Quản Lý phê duyệt...","SCN":"根据该方针指示，传达获得管理局认可的\\n组织间的联盟建立草案……","DEU":"Anbei befindet sich ein auf Grundlage dieser neuen Politik verfasster Entwurf\\ndes Koalitionsvorschlags für die von der Administration befürworteten Organisationen.","FRA":"Conformément à cette nouvelle politique, vous trouverez ci-joint un brouillon\\nde la proposition de coalition entre les organisations approuvées par l'Administration..."},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 부사장님. 아직 남아 계셨네요.","JPN":"あら、副社長。まだ残業されてたんですね。","ENG":"Oh, Vice President. You're still here.","TWN":"哎呀，副總，您還沒走啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 관리국에서 공문이 왔더군요.","JPN":"ええ。管理局から文書が届きまして。","ENG":"Yes. The Administration sent us an official memo.","TWN":"是的，因為管理局發來了公文。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"금방 끝날 테니 먼저 퇴근하세요. 요즘 제시간에 퇴근한 적이 없는 것 같던데.","JPN":"すぐに済ませますので、先に上がってください。\\n最近は定時に帰れていないでしょう？","ENG":"I won't be long. Please go ahead and go home. I've hardly seen you leave work on time lately.","TWN":"我馬上就好了，妳先下班吧。妳不是已經很久沒有準時下班了嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 그러는 부사장님께선 예전이나 지금이나 늦게까지 계시잖아요.","JPN":"ふふっ。そういう副社長は今も昔も変わらず遅くまでおられますよね。","ENG":"Heh heh. But you've always been burning the midnight oil here.","TWN":"呵呵，副總從以前到現在，不也都留得很晚嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"회사에 여유가 생겼는데 가끔은 개인 시간도 가지셔야죠.","JPN":"会社も軌道に乗ってきたことですし、\\nたまにはプライベートの時間を過ごされてもいいと思いますよ。","ENG":"You should take some personal time. The company is doing well these days.","TWN":"公司情況也好轉了，您偶爾也該享受一下個人的時間吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"전 얼마 전에 고등학교 동창들을 만났는데, 꼭 그 때로 돌아간 기분이더라고요.","JPN":"この前、高校の同窓会に行ってきたんですが、\\nまるで昔に戻ったような気分になりました。","ENG":"As for me, I met a few of my classmates from high school recently and it felt like the good old times again.","TWN":"我前幾天和高中同學聚會，感覺就像回到我的少女時代一樣呢！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"부사장님도 오랜만에 젊은 시절 친구 분들과 만나서 기분전환을 해 보시는 건 어떠세요?","JPN":"副社長も久しぶりに若い頃の友人にお会いして、\\n気分転換でもされてみてはどうでしょう？","ENG":"Why don't you also spend some time catching up with old friends? It can be quite refreshing.","TWN":"副總不如也久違地去見見年輕時候的朋友，稍微轉換一下心情如何？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아......!","JPN":"あっ……！","ENG":"Oh...","TWN":"啊……！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저기, 그러니까 부사장님이 나이 드셨다는 뜻은 아니었어요. 제 말은......","JPN":"えっと、その、副社長がお年を召されたと\\n言いたかったわけじゃないんです。私が言いたかったのは……","ENG":"I didn't mean to say that you're old... What I meant was...","TWN":"那個，我不是說您老了，我是說……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"気にしなくて大丈夫ですよ。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고...... 제 예전 친구들은 대부분 연락이 끊겨서요.","JPN":"ただ……昔の友人とはほとんど連絡が途絶えてしまったんです。","ENG":"Besides... I've lost touch with most of my old friends.","TWN":"還有……我和我以前的朋友幾乎都沒有聯絡了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};